import 'package:flutter/material.dart';import '../../../core/constants/app_colors.dart';import '../../../core/routes/app_routes.dart';class SplashScreen extends StatefulWidget {  const SplashScreen({super.key});  @override  State<SplashScreen> createState() => _SplashScreenState();}class _SplashScreenState extends State<SplashScreen>    with SingleTickerProviderStateMixin {  late AnimationController _controller;  late Animation<double> _fadeAnim;  late Animation<double> _scaleAnim;  @override  void initState() {    super.initState();    _controller = AnimationController(      vsync: this,      duration: const Duration(milliseconds: 1500),    );    _fadeAnim = CurvedAnimation(parent: _controller, curve: Curves.easeIn);    _scaleAnim = Tween<double>(begin: 0.8, end: 1.0).animate(      CurvedAnimation(parent: _controller, curve: Curves.easeOutBack),    );    _controller.forward();    Future.delayed(const Duration(milliseconds: 2500), () {      if (mounted) {        Navigator.pushReplacementNamed(context, AppRoutes.welcome);      }    });  }  @override  void dispose() {    _controller.dispose();    super.dispose();  }  @override  Widget build(BuildContext context) {    return Scaffold(      body: Container(        decoration: const BoxDecoration(          gradient: LinearGradient(            begin: Alignment.topLeft,            end: Alignment.bottomRight,            colors: [              AppColors.maroon500,              AppColors.maroon600,              AppColors.maroon700,            ],          ),        ),        child: Stack(          children: [            Positioned.fill(              child: CustomPaint(painter: _DotPainter()),            ),            Center(              child: FadeTransition(                opacity: _fadeAnim,                child: ScaleTransition(                  scale: _scaleAnim,                  child: Column(                    mainAxisSize: MainAxisSize.min,                    children: [                      Container(                        width: 100,                        height: 100,                        decoration: BoxDecoration(                          color: Colors.white.withOpacity(0.1),                          borderRadius: BorderRadius.circular(24),                        ),                        padding: const EdgeInsets.all(16),                        child: Image.asset(                          'assets/images/whitelogo.png',                          fit: BoxFit.contain,                        ),                      ),                      const SizedBox(height: 20),                      const Text(                        'TUNDA',                        style: TextStyle(                          fontSize: 32,                          fontWeight: FontWeight.w900,                          color: AppColors.white,                          letterSpacing: 4,                        ),                      ),                      const SizedBox(height: 8),                      Text(                        'Find Your Perfect Match',                        style: TextStyle(                          fontSize: 14,                          color: AppColors.maroon100,                          fontWeight: FontWeight.w500,                        ),                      ),                      const SizedBox(height: 32),                      SizedBox(                        width: 28,                        height: 28,                        child: CircularProgressIndicator(                          strokeWidth: 2.5,                          valueColor: AlwaysStoppedAnimation(                            AppColors.maroon100.withOpacity(0.6),                          ),                        ),                      ),                    ],                  ),                ),              ),            ),          ],        ),      ),    );  }}class _DotPainter extends CustomPainter {  @override  void paint(Canvas canvas, Size size) {    const spacing = 24.0;    final paint = Paint()      ..color = Colors.white.withOpacity(0.06)      ..style = PaintingStyle.fill;    for (double x = 0; x < size.width; x += spacing) {      for (double y = 0; y < size.height; y += spacing) {        canvas.drawCircle(Offset(x, y), 1.2, paint);      }    }  }  @override  bool shouldRepaint(covariant CustomPainter oldDelegate) => false;}